import json
import yaml
from pathlib import Path
from typing import Literal
import anthropic

SCORING_METHODS = Literal["exact_match", "llm_judge", "rule_based"]

client = anthropic.Anthropic()

def load_eval_cases(suite_dir: str) -> dict[str, dict]:
    """Load all eval cases, keyed by case ID."""
    cases = {}
    for f in Path(suite_dir).glob("EVAL-*.json"):
        case = json.loads(f.read_text())
        cases[case["id"]] = case
    return cases

def grade_llm_judge(output: str, expected_behavior: str, model: str = "claude-haiku-4-5") -> bool:
    """Use a fast model as judge for semantic grading."""
    resp = client.messages.create(
        model=model, max_tokens=5,
        messages=[{"role": "user", "content": (
            f"Expected: {expected_behavior}
Actual: {output}
"
            "Does actual satisfy expected? Reply PASS or FAIL only."
        )}]
    )
    return "PASS" in resp.content[0].text.upper()

def grade_exact_match(output: str, expected: str) -> bool:
    return output.strip().lower() == expected.strip().lower()

def run_eval_suite(
    spec_path: str,
    suite_dir: str,
    system_prompt: str,
    model: str = "claude-sonnet-4-5",
) -> dict:
    spec = yaml.safe_load(Path(spec_path).read_text())
    threshold = spec["current_threshold"]
    criteria = {ac["id"]: ac for ac in spec["acceptance_criteria"]}
    eval_cases = load_eval_cases(suite_dir)

    results_by_ac: dict[str, list[bool]] = {ac_id: [] for ac_id in criteria}

    for eval_id, case in eval_cases.items():
        resp = client.messages.create(
            model=model, max_tokens=512, system=system_prompt,
            messages=[{"role": "user", "content": case["input"]}]
        )
        output = resp.content[0].text

        method = case.get("scoring_method", "llm_judge")
        if method == "exact_match":
            passed = grade_exact_match(output, case["expected_output"])
        else:
            passed = grade_llm_judge(output, case["expected_behavior"])

        for ac_id in case["maps_to"]:
            if ac_id in results_by_ac:
                results_by_ac[ac_id].append(passed)

    coverage_matrix = {}
    gate_passed = True
    for ac_id, passes in results_by_ac.items():
        if not passes:
            coverage_matrix[ac_id] = {"status": "NO_TESTS", "pass_rate": None}
            gate_passed = False
            continue
        rate = sum(passes) / len(passes)
        ac_threshold = threshold  # can override per AC if spec defines it
        coverage_matrix[ac_id] = {
            "pass_rate": round(rate, 3),
            "n_cases": len(passes),
            "threshold": ac_threshold,
            "status": "PASS" if rate >= ac_threshold else "FAIL",
        }
        if rate < ac_threshold:
            gate_passed = False

    return {"gate_passed": gate_passed, "coverage": coverage_matrix, "threshold": threshold}

if __name__ == "__main__":
    result = run_eval_suite(
        spec_path="specs/invoice-extraction.yaml",
        suite_dir="tests/evals/invoice-extraction/",
        system_prompt=Path("prompts/invoice-extraction.txt").read_text(),
    )
    print(json.dumps(result, indent=2))
    exit(0 if result["gate_passed"] else 1)
